select p as product_id, coalesce(round(sum(totalPrice)::numeric / sum(units)::numeric,2),0) as average_price from (select Prices.product_id as p, price * units as totalPrice,UnitsSold.product_id , units from Prices left outer join UnitsSold on (Prices.start_date <= UnitsSold.purchase_date and Prices.end_date >= UnitsSold.purchase_date) and (Prices.product_id = UnitsSold.product_id) )as res group by p